package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private PrintStream originalOut;

    @BeforeEach
    void setUp() {
        // Save the original System.out
        originalOut = System.out;
    }

    @AfterEach
    void tearDown() {
        // Restore original System.out
        System.setOut(originalOut);
    }

    @Test
    void testPrinter_DefaultCSVFormat() throws IOException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVPrinter printer = csvFormat.printer();
        assertNotNull(printer);
        // The printer should use System.out as output and the CSVFormat instance
        assertSame(csvFormat, printer.getFormat());
    }

    @Test
    void testPrinter_CustomCSVFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.DEFAULT.withDelimiter(';').withQuote('|');
        CSVPrinter printer = customFormat.printer();
        assertNotNull(printer);
        assertSame(customFormat, printer.getFormat());
    }
}
